INSERT INTO catalog.product_bundles (bundle_product_id, component_product_id, quantity) SELECT b.id, p.id, v.qty FROM catalog.products b CROSS JOIN (VALUES ('PA-02-0037',1),('PA-08-0002',1),('PA-04-0001',1),('SP-01-0002',1),('MI-07-0002',1)) AS v(sku,qty) JOIN catalog.products p ON p.sku = v.sku WHERE b.name = 'PACK HB 49" DIGITAL SIGNAGE' AND b.product_type = 'BUNDLE' AND NOT EXISTS (SELECT 1 FROM catalog.product_bundles pb WHERE pb.bundle_product_id = b.id);
